import java.io.ByteArrayInputStream;
import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import org.w3c.dom.Document;

public class SoapService {
    public static void main(String[] args) throws Exception {
        // Create a DocumentBuilder to parse incoming SOAP messages
        DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
        factory.setNamespaceAware(true);
        DocumentBuilder builder = factory.newDocumentBuilder();

        // Parse the incoming SOAP message and create a DOM document
        String soapMessage = "<soap:Envelope xmlns:soap=\"http://www.w3.org/2003/05/soap-envelope/\">" +
                "<soap:Header>" +
                "<wsse:Security xmlns:wsse=\"http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-wssecurity-secext-1.0.xsd\">" +
                "<wsse:UsernameToken>" +
                "<wsse:Username>username</wsse:Username>" +
                "<wsse:Password Type=\"http://docs.oasis-open.org/wss/2004/01/oasis-200401-wss-username-token-profile-1.0#PasswordText\">password</wsse:Password>" +
                "</wsse:UsernameToken>" +
                "</wsse:Security>" +
                "</soap:Header>" +
                "<soap:Body>" +
                "<m:GetLastTradePrice xmlns:m=\"http://www.example.org/\">" +
                "<m:symbol>IBM</m:symbol>" +
                "</m:GetLastTradePrice>" +
                "</soap:Body>" +
                "</soap:Envelope>";
        ByteArrayInputStream inputStream = new ByteArrayInputStream(soapMessage.getBytes());
        Document document = builder.parse(inputStream);

        // Handle complex XML structures with nested entities
        NodeList nodeList = document.getElementsByTagName("m:GetLastTradePrice");
        for (int i = 0; i < nodeList.getLength(); i++) {
            Node node = nodeList.item(i);
            if (node.getNodeType() == Node.ELEMENT_NODE) {
                Element element = (Element) node;
                String symbol = element.getElementsByTagName("m:symbol").item(0).getTextContent();
                System.out.println("Symbol: " + symbol);
            }
        }

        // Process large XML payloads for data import
        NodeList payloadNodes = document.getElementsByTagName("payload");
        for (int i = 0; i < payloadNodes.getLength(); i++) {
            Node payloadNode = payloadNodes.item(i);
            if (payloadNode.getNodeType() == Node.ELEMENT_NODE) {
                Element payloadElement = (Element) payloadNode;
                String payload = payloadElement.getTextContent();
                System.out.println("Payload: " + payload);
            }
        }
    }
}